<?php
$office_id   = (int) get_post_meta(get_the_ID(), '_office_id', true);
$department  = get_post_meta(get_the_ID(), '_department', true);

$office_name  = '';
$office_phone = '';
$office_email = '';

if ($office_id) {
	$office_name = get_the_title($office_id);

	switch ($department) {
		case 'residential-sales':
			$office_phone = get_post_meta($office_id, '_office_telephone_number_sales', true);
			$office_email = get_post_meta($office_id, '_office_email_address_sales', true);
			break;

		case 'residential-lettings':
			$office_phone = get_post_meta($office_id, '_office_telephone_number_lettings', true);
			$office_email = get_post_meta($office_id, '_office_email_address_lettings', true);
			break;

		case 'commercial':
			$office_phone = get_post_meta($office_id, '_office_telephone_number_commercial', true);
			$office_email = get_post_meta($office_id, '_office_email_address_commercial', true);
			break;
	}
}
